import React, { useState } from "react";
import { motion } from "framer-motion";

const AnimatedSection = ({ children, style }) => {
  const [clicked, setClicked] = useState(false);
  const [hovering, setHovering] = useState(false);

  const baseBackground = "#1f1f1f"; // fondo base oscuro similar al de tu página
  const hoverBackground = "#154734";
  const baseTextColor = "black";
  const hoverTextColor = "#ddcba4";

  return (
    <motion.section
      initial={{ backgroundColor: baseBackground, scale: 1 }}
      animate={{
        scale: clicked ? 1.05 : 1,
        backgroundColor: hovering ? hoverBackground : baseBackground,
        color: hovering ? hoverTextColor : baseTextColor,
      }}
      transition={{
        duration: clicked ? 3 : 0.3,
        type: "spring",
      }}
      onClick={() => {
        setClicked(true);
        setTimeout(() => setClicked(false), 3000); // vuelve después de 3 segundos
      }}
      onMouseEnter={() => setHovering(true)}
      onMouseLeave={() => setHovering(false)}
      style={{
        cursor: "pointer",
        borderRadius: "1rem",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        maxWidth: "1400px",
        margin: "0 auto 6rem",
        flexWrap: "wrap",
        color: baseTextColor, // se sobrescribe dinámicamente
        ...style,
      }}
    >
      {children}
    </motion.section>
  );
};

export default AnimatedSection;
